/// Return the original pointer value if V is a ptrtoint optionally followed by
/// one or more truncs, otherwise nullptr.
static const Value *getPointerFromPtrDiffOperand(const Value *V) {
  const Value *Op = V;
  while (match(Op, m_Trunc(m_Value(Op))))
